    @Test
    @DisplayName("TC11: Structure separator between two variables produces VARIABLE_OR_CONSTANT, STRUCTURE_SEPARATOR, VARIABLE_OR_CONSTANT tokens")
    void test_TC11() throws Exception {
        // GIVEN a config that allows structures so '.' is recognized and not part of number
        ExpressionConfiguration cfg = mock(ExpressionConfiguration.class);
        when(cfg.getOperatorDictionary()).thenReturn(mock(OperatorDictionaryIfc.class));
        when(cfg.getFunctionDictionary()).thenReturn(mock(FunctionDictionaryIfc.class));
        when(cfg.isStructuresAllowed()).thenReturn(true);
        when(cfg.isArraysAllowed()).thenReturn(false);
        when(cfg.isImplicitMultiplicationAllowed()).thenReturn(false);
        when(cfg.isSingleQuoteStringLiteralsAllowed()).thenReturn(false);

        String expr = "a.b";
        Tokenizer tz = new Tokenizer(expr, cfg);

        // WHEN
        List<Token> tokens = tz.parse();

        // THEN
        assertEquals(3, tokens.size(), "Expect exactly three tokens");
        assertEquals(Token.TokenType.VARIABLE_OR_CONSTANT, tokens.get(0).getType());
        assertEquals("a", tokens.get(0).getTokenValue());
        assertEquals(Token.TokenType.STRUCTURE_SEPARATOR, tokens.get(1).getType());
        assertEquals(".", tokens.get(1).getTokenValue());
        assertEquals(Token.TokenType.VARIABLE_OR_CONSTANT, tokens.get(2).getType());
        assertEquals("b", tokens.get(2).getTokenValue());
    }

